var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":" 세상에, 재클린 경도 저렇게 맥없이 쓰러지다니……!","JPN":" そんな、ジャクリーン卿でさえあんなにあっけなく倒れるなんて……！","ENG":"Oh my, even Sir Jacques has fallen so easily...!","TWN":"哇，竟然連杰克林卿也敗陣下來……！"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":" 도전자들 중에 한 번이라도 공격을 버틴 사람이 없었어…….","JPN":" 挑戦者の中に一度でも攻撃に耐えた者がいなかった……","ENG":"None of the challengers have been able to withstand a single attack...","TWN":"挑戰者當中，完全沒有人可以抵擋攻勢……"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":" 역시 황태자 전하시다! 아르카데나 제국 최강의 무인이야!","JPN":" さすが皇太子殿下だ！　アルカデナ帝国最強の武人だ！","ENG":"Truly he is the Crown Prince! He is the greatest warrior in all of Arcadena!","TWN":"真不愧是皇太子殿下！艾爾卡特納帝國武功最強的人！"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":" 전하야말로 틀림없는 구원자시다! 마왕 네헤모트를 무찌르고 평화를 가져와 주실 게 틀림없어!","JPN":" 殿下こそ正真正銘の救世主だ！　魔王ネヘモトを打ち破り、平和をもたらしてくれるに違いない！","ENG":"There is no doubt that His Highness is the Savior! Surely he will defeat the Demon Lord Nehemoth and bring peace to the world!","TWN":"殿下才是真正的救贖者！殿下會打敗魔王 貝赫莫特帶來和平！"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":" 전하, 어째서 돌아오신 겁니까?","JPN":" 殿下、どうしてお戻りになったのですか？","ENG":"Your Highness, why have you returned?","TWN":"殿下怎麼回來了？"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 배우 노릇을 하는 것도 무료하더군. 잠시 쉬어야겠어.","JPN":" 俳優の真似もつまらないものだ。しばらく休むぞ。","ENG":"I grow weary of putting up a performance. I wish to rest for a while.","TWN":"演戲也是蠻累人的，我要休息一下。"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":" 최후의 승자가 되려면 해가 지기 전까지 경기장을 지키고 있어야 합니다. 아시잖습니까.","JPN":" 最後の勝者になるためには日が暮れる前まで競技場を守らなければなりません。ご存じではありませんか。","ENG":"You must secure your place in the arena until the sun sets if you wish to be declared the final victor. Surely you know this.","TWN":"殿下應該也很清楚，要成為最後的贏家，就必須在日落前守住競技場。"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 알렌 경도 관중들의 분위기를 느끼지 않았나?","JPN":" アレン卿も観衆の雰囲気を感じただろう。","ENG":"You must have also felt the atmosphere of the public, Sir Allen.","TWN":"艾倫卿不是也有感受到群眾的氛圍嗎？"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 저렇게 경도된 군중 앞에 나설 만한 인물은 그리 많지 않다. ","JPN":" あのように傾倒した群衆を前にして出られる人物はそうそう多くあるまい。 ","ENG":"Few can hope to stand in front of such a devoted crowd.","TWN":"在那樣的群眾壓力之下，還能站出來的人應該不多。"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 그나마 재클린 경이 마지막이었지. 더 기다려 봤자 시간 낭비에 불과해.","JPN":" ジャクリーン卿が最後だったぞ。待っていても時間の無駄に過ぎん。","ENG":"Sir Jacques was probably the last of those who possessed that potential. Waiting any longer is a waste of time.","TWN":"杰克林卿應該是最後一個，再等下去也是浪費時間而已。"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":" …….","JPN":" ……","ENG":"...","TWN":"……"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 마지막 승자가 성녀를 지명하고 성녀에게 구원자로 공인 받는단 말이지…….","JPN":" 最後の勝者が聖女を指名し、聖女から救世主として公認される、か……","ENG":"So, the final victor will appoint the Saintess and be officiated by the Saintess as the Savior...","TWN":"最後的贏家可以指定聖女人選，再由聖女承認為救贖者……"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 옛 일화를 맹목적으로 답습할 뿐인 참으로 고리타분한 절차 아닌가.","JPN":" 昔の逸話を盲目的に踏襲するだけの、まったく古くさい手続きではないか。","ENG":"Truly it is an old-fashioned procedure that blindly follows an old folktale.","TWN":"這不過就是承襲古老習俗的迂腐程序不是嗎？"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":" ……전하, 그 절차에 대해서입니디만.","JPN":" ……殿下、その手続きについてですが。","ENG":"Your Highness... about that procedure...","TWN":"……殿下，關於程序這件事。"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 그래. 뻔한 내용 같지만, 어디 말해 보도록.","JPN":" ああ。わかりきった内容だと思うが、話してみろ。","ENG":"Yes. I already know where you are going with this, but ask away.","TWN":"說吧，雖然我知道你要說什麼，不過你還是說吧。"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":" 정말 남쪽의 신전장을 성녀로 지명하실 겁니까?","JPN":" 本当に南方の神殿長を聖女に指名するおつもりですか？","ENG":"Do you seriously plan on appointing the Head Priestess of the South as the Saintess?","TWN":"殿下當真要指定南方的祭司長為聖女嗎？"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 그렇다. 구원자의 첫 행보가 배신한 성녀를 처단하는 것이면 꽤나 파격적일 테지.","JPN":" そうだ。救世主の第一歩が裏切った聖女の処断となれば、ずいぶんと型破りに見えるだろう。","ENG":"Correct. It will be a sight to see the Savior punish the traitorous Saintess as his first feat.","TWN":"沒錯，救贖者的第一步是要處決犯罪的聖女，這應該是很意外的展開吧。"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 희극에서 비극으로 돌아서는 지점이니 관중들도 깊은 인상을 받을 것이다.","JPN":" 喜劇が悲劇に変わるわけだから、観衆も深い印象を受けるはずだ。","ENG":"As this will be the incident which turns triumph into tragedy, it will leave a lasting impression on the public.","TWN":"瞬間從喜劇轉成悲劇，觀眾們應該也會印象很深刻吧。"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};